mapper.select:
select l.log_id, l.product_id, p.product_name, l.warehouse_id, w.warehouse_name,
       l.area_id, l.location_id, l.shelf_id, l.bill_id, l.bill_no, l.bill_type, l.change_type,
       l.change_quantity, l.before_quantity, l.after_quantity, l.operator_id, u.user_name as operator_name,
       l.create_time, l.remark
from wms_inventory_log l
left join prd_product p on p.product_id = l.product_id
left join wms_warehouse w on w.warehouse_id = l.warehouse_id
left join sys_user u on u.user_id = l.operator_id

    and l.product_id = #{productId}
    and l.bill_id = #{billId}
    and l.change_type = #{changeType}
    and l.create_time >= #{beginTime}
    and l.create_time <= #{endTime}

order by l.create_time desc
